summary {
  cursor: pointer;
  list-style: none; /* hides default triangle in Firefox */
  font-weight: 600;
  padding: 1rem;
  border-bottom: 1px solid #e5e7eb;
}

summary::-webkit-details-marker {
  display: none; /* hides triangle in Safari/Chrome */
}

/* Custom open/close indicator */
summary::after {
  content: '+';
  float: right;
  font-size: 1.25rem;
}

details[open] summary::after {
  content: '−';
}

details > :not(summary) {
  padding: 1rem;
}
